UPDATE companies SET description = 'Kaufmann Spezialfahrzeuge ist ein TÜV-geprüfter und zertifizierter Fachbetrieb für Abschlepp-, Bergungs- und Pannendienste im Raum Hoppegarten an der Autobahn A 10. Das Unternehmen bietet Ladekraneinsätze, Maschinentransporte und verschiedene Transportleistungen rund um die Uhr an. Die Abrechnung erfolgt über alle gängigen Versicherungen, Schutzbriefanbieter und Automobilclubs.' WHERE id = '6bdd2af6-bc2a-436c-910e-2a3c4f3fc9af';
UPDATE companies SET description = '4K-Vierke Bau ist ein Experte für Kranvermietung in Berlin und Brandenburg mit einem umfangreichen Maschinenpark (Krane, Arbeitsbühnen, Transportgeräte). Das Unternehmen bietet zusätzlich professionelle Montagedienstleistungen und ist spezialisiert als VELUX Service Partner für Tageslichtlösungen wie Lichtkuppeln, Dachfenster und Lichtbänder.' WHERE id = '38b2a6d3-f34a-49ab-bc91-78fcd2649388';
UPDATE companies SET description = 'a24team ist ein Umzugs- und Lagerungsunternehmen mit Sitz in Berlin. Das Unternehmen bietet Möbelliftmieten ab 150€ für bis zu eine Stunde mit Begleitpersonal an. Sie bieten Service aus einer Hand für Umzüge, Lagerung und Entsorgung bundesweit und europaweit an.' WHERE id = 'f9dc40da-3ce2-4db0-b910-3f02c614619e';
UPDATE companies SET description = 'Die Ludwig GmbH ist ein Abschleppdienst für PKW, LKW und BUS mit Kranservice. Das Unternehmen bietet eine Autokran-Vermietung für Bau, Logistik, Veranstaltungen und besondere Einsätze an. Die Firma steht für Qualität und Zuverlässigkeit und ist rund um die Uhr erreichbar.' WHERE id = 'd9e44fce-c581-451e-81d1-c5f6fe867d5c';
UPDATE companies SET description = 'AK Verleih GmbH ist ein Vermietungsunternehmen für Arbeitsbühnen, Autokräne und Stapler mit 12 Jahren Erfahrung und 2000 Partnern. Das Unternehmen bietet 24-Stunden-Vermietung bundesweit und europaweit mit schnellem, preiswertem Service. Das Leistungsportfolio umfasst auch Container, Gabelstapler und Teleskop-Stapler.' WHERE id = 'f2c35770-2bcb-49a0-bdcf-bd6a439d6134';
UPDATE companies SET description = 'Akkus Bew. & Kranservice GmbH bietet geschultes und erfahrenes Baupersonal für sämtliche Bauvorhaben an. Das Unternehmen ist spezialisiert auf alle Krantypen und vermittelt Kranfahrer, Bagger- und Staplerfahrer sowie weiteres Baupersonal auf nationaler und internationaler Ebene.' WHERE id = 'd800d49c-17ac-4b60-bd07-9ddf90806b1a';
UPDATE companies SET description = 'AKM Autokranvermietung GmbH ist ein Kranvermietungsunternehmen in München, das umfassende Dienstleistungen im Bereich Kranverleih, Schwertransporte und Industriemontagen anbietet. Das Unternehmen verfügt über ein vielfältiges Geräteportfolio einschließlich mobiler Baukrane, Autokrane, Stadt- und Citykrane sowie Arbeitsbühnen und Ladekrane.' WHERE id = '931e8e05-0b56-477f-b413-445b067926eb';
UPDATE companies SET description = 'AKMS Fehrbellin ist ein Autokran-Vermietungsunternehmen mit einem Fuhrpark von 5 Fahrzeugen. Das Unternehmen vermietet Autokrane mit Traglasten von 25 t bis 100 t und garantiert sichere Einsätze mit technisch modernen Fahrzeugen.' WHERE id = '442d50e7-9aea-4fe2-9436-5ba09a13c397';
UPDATE companies SET description = 'Alb-Mietpark Muschenich ist ein Vermietungsunternehmen mit umfassendem Miet-Sortiment. Das Angebot umfasst Minibagger, Bagger, Radlader, Rüttelplatten, Anhänger, Baugeräte, Gartenbaumaschinen, Stromerzeuger, Walzen, Heizgeräte, Kompressoren, Hochdruck-Reiniger und Werkzeuge. Das Sortiment wird ständig erneuert und erweitert.' WHERE id = '69f98cd2-fbb6-4ff0-8cd9-613e8a9d83a2';
UPDATE companies SET description = 'Albert Regel GmbH ist ein Komplettanbieter im Autokran- und Schwertransportsektor mit über 75 Jahren Erfahrung. Das Unternehmen bietet Autokranvermietung, Schwertransporte, Industrie- und Maschinenumzüge sowie weitere Dienstleistungen an. Alle Leistungen sind nach DIN EN ISO 9001:2015 zertifiziert.' WHERE id = 'c436bb0d-af7b-4df2-929a-b1a51a14c0c5';
UPDATE companies SET description = 'Albrecht Autokran GbR ist ein Kranvermietunternehmen mit über 40 Jahren Erfahrung im Bereich mobile Autokrane. Das Unternehmen verfügt über einen umfangreichen Fuhrpark verschiedener Kranmodelle und Transportfahrzeuge sowie spezialisierte Dienstleistungen wie Problembaumfällung und zusätzliche Hebetechniken.' WHERE id = 'e9f3b201-44b4-411f-8d1c-bfdf8155b134';
UPDATE companies SET description = 'Die Alex Grund GmbH ist ein innovativer Partner im Schwerlastbereich für Autokrane und Schwertransporte in Hamburg und Norddeutschland. Das Unternehmen verfügt über einen umfangreichen Fuhrpark mit Mobilkranen, Großkranen, Ladekranen und Sonderkranen bis 400t sowie passendes Zubehör. Neben der Kranvermietung bietet die Firma auch Schwertransporte, Verkehrssicherung, Transportbegleitung und Equipment wie Arbeitsbühnen an.' WHERE id = 'dfd21b35-0cd8-4915-b6f3-b37b5b715ca5';
UPDATE companies SET description = 'Alex Kranservice bietet kompetente Dienstleistungen rund um Kräne an. Das Unternehmen ist spezialisiert auf Kranmontage, Kranwartung und Transporte mit 80 km/h-Achse und hat seinen Sitz in Oberrieden.' WHERE id = 'fdbdafff-c8ee-4676-bcf8-a4b0a3dc0ff2';
UPDATE companies SET description = 'ALL-KRAN Autokrane GmbH & Co. KG ist ein Kranvermietungsunternehmen mit langjähriger Erfahrung in Mittelfranken. Sie bieten Kranvermietung, Baumfällarbeiten und Bergungsservices für private, gewerbliche und kommunale Kunden an. Das Unternehmen zeichnet sich durch Pünktlichkeit, Professionalität und zügige Arbeitsweise aus.' WHERE id = '8b8108fb-b3a9-4582-9ed0-4b1d4b767c58';
UPDATE companies SET description = 'ALL-KRAN Autokrane GmbH & Co. KG ist ein Kranvermietunternehmen mit langjähriger Erfahrung und qualifiziertem Fachpersonal. Das Unternehmen bietet maßgeschneiderte Autokran-Lösungen für private, gewerbliche und kommunale Kunden an und führt auch Baumfällarbeiten und Bergungen durch.' WHERE id = '0f4aebf1-c2a0-45da-a7f2-1a17b29bd1cb';
UPDATE companies SET description = 'ALL-KRAN Autokrane GmbH & Co. KG ist ein Experte für Kranvermietung, Baumfällarbeiten und Bergungen in Mittelfranken. Das Unternehmen bietet langjährige Erfahrung und maßgeschneiderte Lösungen für Private, Gewerbetriebe und Kommunen. Mit qualifiziertem Fachpersonal führen sie Aufträge zuverlässig und zu fairen Preisen durch.' WHERE id = '66589dff-a1bc-4908-ba97-6b7e5971347e';
UPDATE companies SET description = 'ALLeLIFTE GmbH & Co. KG ist ein Partner für Vermietung und Verkauf spezieller Lösungen im Bereich Hebetechnik. Das Unternehmen bietet kompakte Geräte an, die auf engstem Raum einsetzbar sind und durch Normtüren sowie in Aufzüge passen. Zusätzlich zur Vermietung übernehmen sie Wartung, Reparatur und Ersatzteilversorgung deutschlandweit und herstellerunabhängig.' WHERE id = '33681f31-d15a-48ef-8738-6d536f991e7f';
UPDATE companies SET description = 'AMS Arbeitsbühnen GmbH in Hoppegarten vermietet und verkauft Arbeitsbühnen für verschiedenste Anforderungen. Der Fuhrpark umfasst LKW-Arbeitsbühnen, Anhänger-Arbeitsbühnen, Scheren-Arbeitsbühnen, Teleskop-Arbeitsbühnen und weitere Modelle mit Arbeitshöhen bis 60 m. Das Unternehmen bietet zusätzlich Service mit Wartung, Reparatur und Sicherheitsprüfung an.' WHERE id = 'a88d4bf4-2de9-42cf-acc1-3a5510eb1e19';
UPDATE companies SET description = 'Andreas Sauler ist ein Kranvermietungsunternehmen mit 30 Jahren Erfahrung. Das Unternehmen verfügt über Liebherr-Kräne mit einer Ausladung von 24 bis 60 Metern. Das Team bietet professionelle Kranlösungen mit flexiblen Mietoptionen für verschiedene Bauprojekte.' WHERE id = '4f26f38e-4e35-415e-8307-10d33c5e4779';
UPDATE companies SET description = 'Apparillos ist ein Vermiet- und Verkaufsunternehmen für Baumaschinen seit September 2021. Das Unternehmen ist Vertriebspartner der Hersteller JCB und BOMAG und bietet einen modernen Maschinenpark zur Miete und zum Kauf an. Apparillos unterstützt Kunden bei Bauprojekten mit Maschinen wie Rüttelplatten, Minibaggern und großer Technik.' WHERE id = '6304d0a4-f85b-4ac2-95c4-9dbd51ad3230';
UPDATE companies SET description = 'rentem® ist ein Vermietungsunternehmen für Arbeitsbühnen, Hebebühnen und Gabelstapler in Dortmund. Das Unternehmen bietet umfassenden Service inklusive Maschinenführer, Wartung und Logistik. rentem® arbeitet mit namhaften Herstellern wie Toyota, JLG, Genie, Manitou, Still, Linde und Jungheinrich zusammen.' WHERE id = 'dc87076e-37f2-4e0e-9055-db61177cbcee';
UPDATE companies SET description = 'Die Arbeitsbühnen Hoffmann GmbH in Waghäusel im Landkreis Karlsruhe ist ein zuverlässiger Partner für Bauunternehmen, Großveranstalter und Betreiber von Material- und Warenlagern. Das Unternehmen vermietet Arbeitsbühnen, Stapler und Krane mit über 22.000 verfügbaren Geräten an 135 Mietstationen. Sie bieten Online-Mietanfragen rund um die Uhr an.' WHERE id = 'fe174553-0a93-47de-bff2-b78e99995610';
UPDATE companies SET description = 'Unitec Soest ist ein erfahrener Partner für Vermietung, Verkauf und Service von Hebe-, Transport- und Lagertechnik. Das Unternehmen bietet neben Arbeitsbühnen und Kranen auch Container, Stapler und Baumaschinen an. Mit einem modernen Fuhrpark und umfassenden Services wie UVV-Prüfungen, Abschleppdienst und Reifenservice steht Unitec Soest Industrie, Handwerk, Bau und Eventlogistik zur Seite.' WHERE id = '8b4ba27f-b1b3-44af-877f-d8b56a2c85ae';
UPDATE companies SET description = 'Köllner ist ein zuverlässiger und flexibler Partner für die Vermietung von Gabelstaplern und Arbeitsbühnen im Großraum Braunschweig. Seit über zehn Jahren bedienen sie Kunden aus verschiedenen Branchen mit schneller und unkomplizierter Vermietung. Die Firma zeichnet sich durch Zuverlässigkeit, Flexibilität und kurzfristige Verfügbarkeit aus.' WHERE id = '308c543e-fd57-48cf-80ab-d7ee492cc945';
UPDATE companies SET description = 'Arbeitsbühnenvermietung Gebr. März GbR ist ein Anbieter von Arbeitsbühnenvermietung aus dem Lechfeld. Das Unternehmen bietet die Multitel MJ 226 Arbeitsbühne mit Arbeitshöhen bis 22,5 m und flexiblen Mietoptionen an.' WHERE id = 'f1f2226c-72ec-4c1e-98bb-5fde9fcea156';
UPDATE companies SET description = 'Armbruster Autokran-Vermietung ist seit 1979 tätig und bietet über 45 Jahre Branchenerfahrung. Das Unternehmen verfügt über 12 moderne Autokrane und sechs LKW und führt Kranarbeiten, Transporte, Schwertransporte sowie Verkehrssicherung durch. Mit speziell ausgerüstetem Fuhrpark bewältigt Armbruster Hebevorgänge, Transporte und Schwerlasttransporte im Großraum Reutlingen, Tübingen und Stuttgart.' WHERE id = '34d297c9-b81b-472d-9ad6-0312cb613a32';
UPDATE companies SET description = 'ASS - Autokran Schwerlast Service GmbH ist ein Dienstleister im Bereich Krandienstleistungen und Schwertransporte. Das Unternehmen bietet professionelle Hebe-, Montage- und Transportlösungen mit modernen Teleskop-Mobilkranen bis 35 Tonnen Tragfähigkeit für Bau, Industrie und Spezialprojekte.' WHERE id = '3555fa7a-ebc4-455d-bcbb-551c5cbe7d4f';
UPDATE companies SET description = 'ATK-TaunusKran GmbH ist spezialisiert auf Lösungen für die Glasmontage. Das Unternehmen bietet verschiedene Krantypen wie Minikräne und Autokräne sowie Glassauger für den Transport und die Montage von Glasscheiben an. Mit umfangreicher Erfahrung führt das Unternehmen Projekte an verschiedenen Standorten in Deutschland durch.' WHERE id = 'bb186931-a35b-4a12-b33c-31583a4e80c5';
UPDATE companies SET description = 'Atlas Hamburg GmbH ist ein Baumaschinen- und Fahrzeughändler mit über 60 Jahren Erfahrung in dritter Generation. Das Unternehmen bietet Baumaschinen zu fairen Preisen, Vermietung und Fahrzeugbau mit ISO-zertifizierter Produktion. Mit mehreren Standorten in Norddeutschland und einer Mehrmarkenstrategie verfügt die Firma über umfassenden Service rund um die Uhr.' WHERE id = 'befdc05b-c390-4f35-b6e3-6e236dda868d';
UPDATE companies SET description = 'Autokran Heike Hoppe ist ein Kranvermietungsunternehmen in Kaarst, das sich auf kundenorientierte Organisation, Planung und Ausführung von Lasttransporten spezialisiert hat. Das Unternehmen bietet Kranverladung und Kranverleih sowie Komplettlösungen mit langjähriger Erfahrung an. Das Fachpersonal unterstützt Kunden von der Planung bis zur Ausführung ihrer Projekte.' WHERE id = '529c548c-f8a6-436f-8191-ae82d197e916';
UPDATE companies SET description = 'Autokran Müller GmbH & Co. KG ist ein Partner für Kranverleih und -dienstleistungen. Das Unternehmen bietet Autokrane in verschiedenen Traglasten von 50 bis 220 Tonnen sowie Ladekrane bis zu 65 MT an.' WHERE id = '03857fbd-cf5d-4290-b560-46cf9cc8bab0';
UPDATE companies SET description = 'Autokran Müller GmbH & Co. KG ist ein Partner für Kranverleih und -dienstleistungen. Das Unternehmen bietet Autokrane mit Traglasten bis zu 220 Tonnen sowie Ladekrane bis zu 65 MT an.' WHERE id = '591e1cd9-1c05-49a3-a405-58241811611e';
