UPDATE companies SET description = 'WOLFFKRAN GmbH mit Niederlassung in Dortmund ist ein Hersteller und Vermietungsunternehmen von Turmdrehkränen und Laufkatzkränen. Das Unternehmen bietet verschiedene Kranmodelle wie den WOLFF 8095 Compact, WOLFF 8038 Clear und WOLFF 7021 Clear für Großbaustellen an.' WHERE id = '86874a94-8977-4508-9d30-cd237cbfb654';
UPDATE companies SET description = 'Wolfgang Wehr Ladekran-Transporte GmbH & Co. KG ist ein familiengeführtes Unternehmen mit über 20 Jahren Erfahrung in Transportlösungen. Das Unternehmen bietet professionelle Projektplanung, routinierte Fahrer und Monteure sowie eine moderne Fahrzeugflotte basierend auf Mercedes-Benz Actros. Zuverlässigkeit, Flexibilität und Innovation sind die Kernwerte des Unternehmens.' WHERE id = 'd7313927-7d62-426d-8d47-bccce0e98572';
UPDATE companies SET description = 'WR Baumaschinen GbR ist ein Vermietungsunternehmen für Baumaschinen mit günstigen Konditionen und einem ständig erweiterten Fuhrpark. Das Unternehmen bietet Rundum-Sorglos-Vermietung inklusive Versicherung, zuverlässigen Transport und kompetente Einweisung bei Übergabe.' WHERE id = 'd465b787-98f4-4819-b2bd-ef6a5b993243';
UPDATE companies SET description = 'ZAK KRANE GmbH verkauft und vermietet Krane, Teleskopstapler, Scherenarbeitsbühnen und Gelenk- sowie Teleskoparbeitsbühnen. Das Unternehmen bietet persönliche Beratung, professionelle Service und arbeitet mit einem regionalen Netzwerk zusammen. Die Maschinen werden ständig geprüft und sind einsatzbereit.' WHERE id = '40f72a59-e5bd-4d3a-baf7-5eca6ddb213e';
UPDATE companies SET description = 'Zeller Kranservice ist ein Kranvermietungsunternehmen mit Sitz in Werl. Das Team um Geschäftsführer Dirk Zeller bietet verschiedene Krantypen zur Miete an und ist täglich erreichbar.' WHERE id = '7d213a47-175a-442f-8de0-d81cd54ba356';
UPDATE companies SET description = 'ZINK Kranvermietung ist ein kompetenter Partner für LIEBHERR Baustellenkrane und bietet Lösungen für Großbaustellen, Einfamilienhäuser und Dachsanierungen. Das Unternehmen liefert die Krane und führt die Montage durch geschultes Fachpersonal durch. Bei Bedarf wird eine kostenlose Vor-Ort-Beratung zur Auswahl des passenden Kranes angeboten.' WHERE id = 'd887ed02-7568-4066-aada-97f7f119b1d7';
UPDATE companies SET description = 'Zobel & Zobel GbR ist ein kompetenter Partner für die Miete von Bau- und Gartengeräten renommierter Hersteller. Das Unternehmen bietet flexible und verfügbare Lösungen mit unkomplizierter Lieferung und persönlicher Beratung seit 2019.' WHERE id = '205feb08-4bce-4545-98ff-a44e6124720a';

